import{_ as c,o as a,c as o,a3 as d}from"./chunks/framework.aYYe0dfI.js";const h=JSON.parse('{"title":"Module extract:scan","description":"extract:scan 模块是 clore::extract 中负责 C++ 源文件依赖关系扫描与模块信息提取的核心模块。它通过 Clang 的预处理指令扫描器（scan_module_decl）快速获取模块声明、接口单元标识和导入列表，并可基于完整编译数据库对单个文件进行深层扫描（scan_file），返回包含模块名称、导入、包含指令及错误的 ScanResult。同时，该模块支持异步构建模块间的 DependencyGraph（通过 build_dependency_graph_async），并提供了 topological_order 函数对图进行拓扑排序，为后续编译或分析提供有序的依赖列表。","frontmatter":{"title":"Module extract:scan","description":"extract:scan 模块是 clore::extract 中负责 C++ 源文件依赖关系扫描与模块信息提取的核心模块。它通过 Clang 的预处理指令扫描器（scan_module_decl）快速获取模块声明、接口单元标识和导入列表，并可基于完整编译数据库对单个文件进行深层扫描（scan_file），返回包含模块名称、导入、包含指令及错误的 ScanResult。同时，该模块支持异步构建模块间的 DependencyGraph（通过 build_dependency_graph_async），并提供了 topological_order 函数对图进行拓扑排序，为后续编译或分析提供有序的依赖列表。","layout":"doc","template":"doc"},"headers":[],"relativePath":"zh/clore/modules/extract/scan.md","filePath":"zh/clore/modules/extract/scan.md"}'),t={name:"zh/clore/modules/extract/scan.md"};function r(l,e,n,i,s,u){return a(),o("div",null,[...e[0]||(e[0]=[d("",129)])])}const m=c(t,[["render",r]]);export{h as __pageData,m as default};
